#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16
#define ETA 0.3f
#define MOMENTUM 0.3f

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

__kernel void bpnn_layerforward_ocl(__global float *l1,
                                    __global float *l2,
                                    __global float *conn,
                                    __global float *partial_sum,
                                    __local float *local_conn,
                                    __local float *local_l1,
                                    int n1,
                                    int n2) {
    int gid1 = get_global_id(1);
    int gid0 = get_global_id(0);

    int block_id = gid1 / BLOCK_SIZE;
    int j_idx = gid1 % BLOCK_SIZE;
    int j = j_idx + 1;

    if (j > n2) return;

    int k_start = block_id * BLOCK_SIZE;
    int k = k_start + gid0;

    // Load l1 into local memory
    if (k <= n1) {
        local_l1[gid0] = l1[k];
    } else {
        local_l1[gid0] = 0.0f;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float term = 0.0f;
    // Skip k=0 as host adds bias manually
    if (k <= n1 && k != 0) {
        term = conn[k * (n2 + 1) + j] * local_l1[gid0];
    }

    local_conn[gid0] = term;
    barrier(CLK_LOCAL_MEM_FENCE);

    if (gid0 == 0) {
        float sum = 0.0f;
        for (int i = 0; i < BLOCK_SIZE; i++) {
            sum += local_conn[i];
        }
        partial_sum[block_id * n2 + (j - 1)] = sum;
    }
}

__kernel void bpnn_adjust_weights_ocl(__global float *delta,
                                      int ndelta,
                                      __global float *ly,
                                      int nly,
                                      __global float *w,
                                      __global float *oldw) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= ndelta && k <= nly) {
        float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k * (ndelta + 1) + j]);
        w[k * (ndelta + 1) + j] += new_dw;
        oldw[k * (ndelta + 1) + j] = new_dw;
    }
}
